// src/components/DashboardAluno.jsx
import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';
import dayjs from 'dayjs';

const pillClasses = {
  'Solicitado': 'bg-[#FEC139] text-[#555555]',
  'Novo':       'bg-[#2FA74E] text-white',
  'Retorno':    'bg-[#DA3648] text-white'
};

export default function DashboardAluno() {
  const { user } = useAuth();
  const token = user.token;

  const [nome, setNome] = useState('');
  const [agendamentos, setAgendamentos] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    async function load() {
      try {
        // 1) perfil
        const [{ data: perfil }, { data: meusAg }] = await Promise.all([
          axios.get('/api/alunos/me',   { headers:{ Authorization: `Bearer ${token}` }}),
          axios.get('/api/agendamentos/me', { headers:{ Authorization: `Bearer ${token}` }})
        ]);
        setNome(perfil.nome);

        // ensure array
        setAgendamentos(Array.isArray(meusAg) ? meusAg : [meusAg]);
      } catch (err) {
        console.error('Erro ao carregar dashboard:', err.response?.data||err.message);
      } finally {
        setLoading(false);
      }
    }
    load();
  }, [token]);

  if (loading) {
    return <p className="text-center py-8">Carregando dashboard…</p>;
  }

  const hoje = dayjs().startOf('day');
  const solicitacoesPendentes = agendamentos.filter(a => a.status === 'Solicitado').length;
  const proximosAgendamentos = agendamentos.filter(a => {
    return a.status !== 'Solicitado' && dayjs(a.data).isSameOrAfter(hoje);
  }).length;

  const ultimasSolicitacoes = agendamentos
    .filter(a => a.status === 'Solicitado')
    .sort((a,b)=> dayjs(b.data).diff(dayjs(a.data)))
    .slice(0, 5);

  return (
    <div className="p-6 space-y-6">
      {/* Saudação */}
      <h2 className="text-2xl font-bold">
        Olá, {nome.split(' ')[0]}!
      </h2>

      {/* Resumo */}
      <div className="bg-[#D9E0FF] p-4 rounded-2xl grid grid-cols-1 md:grid-cols-2 gap-4">
        <div className="bg-white p-4 rounded-xl shadow text-center">
          <div className="text-3xl font-bold text-[#3172C0]">{solicitacoesPendentes}</div>
          <div className="mt-1 text-sm text-gray-600">Solicitações Pendentes</div>
        </div>
        <div className="bg-white p-4 rounded-xl shadow text-center">
          <div className="text-3xl font-bold text-[#3172C0]">{proximosAgendamentos}</div>
          <div className="mt-1 text-sm text-gray-600">Agendamentos Próximos</div>
        </div>
      </div>

      {/* Últimas Solicitações */}
      <div className="bg-white p-4 rounded-2xl shadow">
        <h3 className="font-semibold mb-3">Últimas Solicitações</h3>
        {ultimasSolicitacoes.length === 0
          ? <p className="text-gray-500">Nenhuma solicitação recente.</p>
          : (
            <ul className="space-y-2">
              {ultimasSolicitacoes.map(a => (
                <li key={a.id} className="flex justify-between items-center">
                  <span>
                    {dayjs(a.data).format('DD/MM/YYYY')}
                  </span>
                  <span className={`px-3 py-1 rounded-full text-xs font-semibold ${pillClasses[a.status]||'bg-gray-200 text-gray-700'}`}>
                    {a.status}
                  </span>
                </li>
              ))}
            </ul>
          )
        }
      </div>
    </div>
  );
}
